class MessageProcessor:
    def __init__(self):
        self.handlers: List[MessageHandler] = []
        self._register_default_handlers()

    def _register_default_handlers(self):
        self.handlers.extend([
            EmailHandler(),
            DataProcessingHandler(),
            NotificationHandler(),
            ReportGenerationHandler(),
            ImageProcessingHandler(),
            WebhookHandler()
        ])

    def register_handler(self, handler: MessageHandler):
        self.handlers.append(handler)

    def process_message(self, message_body: str) -> bool:
        try:
            message_data = json.loads(message_body)
            message_type = message_data.get('type')
            
            if not message_type:
                logger.error("Message type not specified")
                return False

            logger.info(f"Processing message of type: {message_type}")
            
            for handler in self.handlers:
                if handler.can_handle(message_type):
                    return handler.handle(message_data)
            
            logger.warning(f"No handler found for message type: {message_type}")
            return False
            
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse message body: {str(e)}")
            return False
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            return False


class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time_seconds = wait_time_seconds
        self.visibility_timeout = visibility_timeout
        self.running = False
        
        session_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs['aws_access_key_id'] = aws_access_key_id
            session_kwargs['aws_secret_access_key'] = aws_secret_access_key
        
        self.sqs_client = boto3.client('sqs', **session_kwargs)
        self.message_processor = MessageProcessor()
        
        self.stats = {
            'processed': 0,
            'successful': 0,
            'failed': 0,
            'deleted': 0
        }

    def register_custom_handler(self, handler: MessageHandler):
        self.message_processor.register_handler(handler)

    def poll_messages(self) -> List[Dict[str, Any]]:
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All']
            )
            
            messages = response.get('Messages', [])
            logger.info(f"Polled {len(messages)} messages from queue")
            return messages
            
        except Exception as e:
            logger.error(f"Error polling messages from SQS: {str(e)}")
            return []

    def delete_message(self, receipt_handle: str) -> bool:
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            self.stats['deleted'] += 1
            return True
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
            return False

    def change_message_visibility(self, receipt_handle: str, visibility_timeout: int) -> bool:
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=visibility_timeout
            )
            return True
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
            return False

    def process_single_message(self, message: Dict[str, Any]) -> bool:
        message_id = message.get('MessageId')
        receipt_handle = message.get('ReceiptHandle')
        body = message.get('Body')
        
        logger.info(f"Processing message {message_id}")
        
        try:
            success = self.message_processor.process_message(body)
            
            self.stats['processed'] += 1
            
            if success:
                self.stats['successful'] += 1
                self.delete_message(receipt_handle)
                logger.info(f"Message {message_id} processed and deleted successfully")
                return True
            else:
                self.stats['failed'] += 1
                logger.error(f"Message {message_id} processing failed")
                return False
                
        except Exception as e:
            logger.error(f"Unexpected error processing message {message_id}: {str(e)}")
            self.stats['failed'] += 1
            return False

    def process_messages(self, messages: List[Dict[str, Any]]):
        for message in messages:
            self.process_single_message(message)

    def start(self, max_iterations: Optional[int] = None):
        self.running = True
        iterations = 0
        
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")
        
        try:
            while self.running:
                if max_iterations and iterations >= max_iterations:
                    logger.info(f"Reached max iterations ({max_iterations}), stopping worker")
                    break
                
                messages = self.poll_messages()
                
                if messages:
                    self.process_messages(messages)
                else:
                    logger.debug("No messages received, continuing to poll...")
                
                iterations += 1
                
        except KeyboardInterrupt:
            logger.info("Worker interrupted by user")
        except Exception as e:
            logger.error(f"Worker error: {str(e)}")
        finally:
            self.stop()

    def stop(self):
        self.running = False
        logger.info("Stopping SQS worker")
        self.print_stats()

    def print_stats(self):
        logger.info("Worker Statistics:")
        logger.info(f"  Total Processed: {self.stats['processed']}")
        logger.info(f"  Successful: {self.stats['successful']}")
        logger.info(f"  Failed: {self.stats['failed']}")
        logger.info(f"  Deleted: {self.stats['deleted']}")

    def get_stats(self) -> Dict[str, int]:
        return self.stats.copy()


class BatchSQSWorker(SQSWorker):
    def __init__(self, queue_url: str, batch_size: int = 5, **kwargs):
        super().__init__(queue_url, **kwargs)
        self.batch_size = batch_size
        self.message_batch = []

    def process_messages(self, messages: List[Dict[str, Any]]):
        self.message_batch.extend(messages)
        
        while len(self.message_batch) >= self.batch_size:
            batch = self.message_batch[:self.batch_size]
            self.message_batch = self.message_batch[self.batch_size:]
            
            logger.info(f"Processing batch of {len(batch)} messages")
            for message in batch:
                self.process_single_message(message)

    def stop(self):
        if self.message_batch:
            logger.info(f"Processing remaining {len(self.message_batch)} messages")
            for message in self.message_batch:
                self.process_single_message(message)
            self.message_batch = []
        
        super().stop()


